// // This module selects between two input signals, 'Dataout' and 'result', based on the control signal 'memtoreg'. When 'memtoreg' is 0, 'busW' outputs 'Dataout'; when 'memtoreg' is 1, 'busW' outputs 'result'.
module top_module(result,Dataout,memtoreg,busW);input wire memtoreg;
	input wire[31:0] result,Dataout;
	output wire[31:0] busW;

	assign busW=(memtoreg==0)?result:Dataout;
endmodule
